input.command:
cd "C:\Users\Administrator\Desktop\리크 검사기 신진&엔케이\신진" && powershell -ExecutionPolicy Bypass -Command "
# 백업
Copy-Item 'FrmMain.Designer.vb' 'FrmMain.Designer.vb.bak' -Force
Copy-Item 'FrmMain.vb' 'FrmMain.vb.bak' -Force

# ========== FrmMain.Designer.vb 교체 ==========
\$d = [System.IO.File]::ReadAllText('FrmMain.Designer.vb', [System.Text.Encoding]::UTF8)

# --- 1. 생성부 교체 (New AxCWUIControlsLib.AxCWButton → 용도별) ---
# 버튼들
foreach (\$btn in @('ascButtonExit','axcButtonPart','axcButtonSEt','axcButtonSearch','axcButtonSIgnal','AxcButtonCountReset','ascButtonTest','ascButtonTestSearch')) {
    \$d = \$d -replace \"Me\.\$btn = New AxCWUIControlsLib\.AxCWButton\(\)\", \"Me.\$btn = New System.Windows.Forms.Button()\"
}

# LED 패널들
foreach (\$led in @('LedScanner','LedPrinter','LedDIO','LedDIO2','LedDAQ','LedSUpply')) {
    \$d = \$d -replace \"Me\.\$led = New AxCWUIControlsLib\.AxCWButton\(\)\", \"Me.\$led = New System.Windows.Forms.Panel()\"
}

# 나머지 모든 AxCWButton → Label
\$d = \$d -replace 'New AxCWUIControlsLib\.AxCWButton\(\)', 'New System.Windows.Forms.Label()'

# ScatterGraph → ZedGraphControl
\$d = \$d -replace 'New NationalInstruments\.UI\.WindowsForms\.ScatterGraph\(\)', 'New ZedGraph.ZedGraphControl()'

# FlexCell.Grid → DataGridView
\$d = \$d -replace 'New FlexCell\.Grid\(\)', 'New System.Windows.Forms.DataGridView()'

# ScatterPlot, XAxis, YAxis, XYCursor, XYRangeAnnotation 생성 줄 제거
\$lines = \$d -split \"`r?`n\"
\$filtered = @()
foreach (\$line in \$lines) {
    if (\$line -match 'Me\.(ScatterPlot\d+|XAxis\d+|YAxis\d+|XyCursor\d+|XyRangeAnnotation\d+|Range\d+\w+) = New NationalInstruments\.UI\.' -and \$line -notmatch 'srcGraph') {
        continue
    }
    \$filtered += \$line
}
\$d = \$filtered -join \"`r`n\"

# --- 2. BeginInit/EndInit 제거 (NI/AxCW/FlexCell 관련만) ---
\$lines = \$d -split \"`r?`n\"
\$filtered = @()
foreach (\$line in \$lines) {
    if (\$line -match 'CType\(Me\.(XyCursor|ScatterPlot\d|XAxis\d|YAxis\d|srcGraph|lbCellType|src\d|src[1-5]|AxCW|_1st_Lb|asc|axc|Led|AxcButton|Range)' -and (\$line -match 'BeginInit' -or \$line -match 'EndInit')) {
        continue
    }
    \$filtered += \$line
}
\$d = \$filtered -join \"`r`n\"

# --- 3. OcxState 줄 제거 ---
\$lines = \$d -split \"`r?`n\"
\$filtered = @()
foreach (\$line in \$lines) {
    if (\$line -match '\.OcxState\s*=') {
        continue
    }
    \$filtered += \$line
}
\$d = \$filtered -join \"`r`n\"

# --- 4. NI 전용 속성 블록 제거 (ScatterPlot, XAxis, YAxis, XyCursor, Range 속성 설정) ---
# ScatterPlot 속성 블록 제거
\$lines = \$d -split \"`r?`n\"
\$filtered = @()
\$inNIBlock = \$false
\$blockType = ''
foreach (\$line in \$lines) {
    # ScatterPlot/XAxis/YAxis/XyCursor/Range 속성 라인 제거
    if (\$line -match '^\s+Me\.(ScatterPlot\d+|XAxis\d+|YAxis\d+|XyCursor\d+)\.' -and \$line -notmatch 'srcGraph') {
        continue
    }
    # Range annotation 속성 라인 제거
    if (\$line -match '^\s+Me\.(Range\d+\w+|XyRangeAnnotation\d+)\.' -and \$line -notmatch 'srcGraph') {
        continue
    }
    \$filtered += \$line
}
\$d = \$filtered -join \"`r`n\"

# 빈 주석 블록 정리 (연속 ' 줄 사이에 빈 것들)
# ScatterPlot/XAxis/YAxis/XyCursor/Range 주석 블록 제거
\$lines = \$d -split \"`r?`n\"
\$filtered = @()
\$i = 0
while (\$i -lt \$lines.Count) {
    if (\$lines[\$i] -match \"^\s+'$\" -and (\$i+1) -lt \$lines.Count -and \$lines[\$i+1] -match \"^\s+'(ScatterPlot\d+|XAxis\d+|YAxis\d+|XyCursor\d+|Range\d+\w+|XyRangeAnnotation\d+)$\" -and (\$i+2) -lt \$lines.Count -and \$lines[\$i+2] -match \"^\s+'$\") {
        # Skip 3 lines (comment block header)
        \$i += 3
        continue
    }
    \$filtered += \$lines[\$i]
    \$i++
}
\$d = \$filtered -join \"`r`n\"

# --- 5. srcGraph 속성 교체 ---
# srcGraph NI 전용 속성 제거 (Border, Caption, CaptionFont, InteractionMode, PlotAreaColor, Plots, UseColorGenerator, XAxes, YAxes, Annotations)
\$lines = \$d -split \"`r?`n\"
\$filtered = @()
\$skipMultiline = \$false
foreach (\$line in \$lines) {
    if (\$skipMultiline) {
        if (\$line -match 'GraphInteractionModes\)$') {
            \$skipMultiline = \$false
        }
        continue
    }
    if (\$line -match '^\s+Me\.srcGraph\w+\.(Border|Caption|CaptionFont|PlotAreaColor|UseColorGenerator) =') {
        continue
    }
    if (\$line -match '^\s+Me\.srcGraph\w+\.InteractionMode =') {
        \$skipMultiline = \$true
        continue
    }
    if (\$line -match '^\s+Me\.srcGraph\w+\.(Plots|XAxes|YAxes|Annotations)\.AddRange') {
        continue
    }
    \$filtered += \$line
}
\$d = \$filtered -join \"`r`n\"

# --- 6. GridCount FlexCell 속성 교체 ---
\$d = \$d -replace 'Me\.GridCount\.BorderStyle = FlexCell\.BorderStyleEnum\.FixedSingle', 'Me.GridCount.BorderStyle = System.Windows.Forms.BorderStyle.FixedSingle'
\$d = \$d -replace 'Me\.GridCount\.ScrollBars = FlexCell\.ScrollBarsEnum\.None', 'Me.GridCount.ScrollBars = System.Windows.Forms.ScrollBars.None'
# GridCount FlexCell 전용 속성 제거
\$lines = \$d -split \"`r?`n\"
\$filtered = @()
foreach (\$line in \$lines) {
    if (\$line -match '^\s+Me\.GridCount\.(CheckedImage|DefaultFont|DefaultRowHeight|GridColor|UncheckedImage) =') {
        continue
    }
    \$filtered += \$line
}
\$d = \$filtered -join \"`r`n\"

# --- 7. Friend WithEvents 선언부 교체 ---
# 버튼
foreach (\$btn in @('ascButtonExit','axcButtonPart','axcButtonSEt','axcButtonSearch','axcButtonSIgnal','AxcButtonCountReset','ascButtonTest','ascButtonTestSearch')) {
    \$d = \$d -replace \"Friend WithEvents \$btn As AxCWUIControlsLib\.AxCWButton\", \"Friend WithEvents \$btn As System.Windows.Forms.Button\"
}
# LED 패널
foreach (\$led in @('LedScanner','LedPrinter','LedDIO','LedDIO2','LedDAQ','LedSUpply')) {
    \$d = \$d -replace \"Friend WithEvents \$led As AxCWUIControlsLib\.AxCWButton\", \"Friend WithEvents \$led As System.Windows.Forms.Panel\"
}
# 나머지 AxCWButton → Label
\$d = \$d -replace 'Friend WithEvents (\w+) As AxCWUIControlsLib\.AxCWButton', 'Friend WithEvents \$1 As System.Windows.Forms.Label'

# ScatterGraph → ZedGraphControl
\$d = \$d -replace 'Friend WithEvents (\w+) As WindowsForms\.ScatterGraph', 'Friend WithEvents \$1 As ZedGraph.ZedGraphControl'

# FlexCell.Grid → DataGridView
\$d = \$d -replace 'Friend WithEvents GridCount As FlexCell\.Grid', 'Friend WithEvents GridCount As System.Windows.Forms.DataGridView'

# ScatterPlot, XAxis, YAxis, XYCursor, XYRangeAnnotation 선언 제거
\$lines = \$d -split \"`r?`n\"
\$filtered = @()
foreach (\$line in \$lines) {
    if (\$line -match 'Friend WithEvents \w+ As (ScatterPlot|XAxis|YAxis|XYCursor|XYRangeAnnotation)$') {
        continue
    }
    \$filtered += \$line
}
\$d = \$filtered -join \"`r`n\"

# --- 8. LED Panel에 BackColor 추가 (Size 다음 줄에) ---
foreach (\$led in @('LedScanner','LedPrinter','LedDIO','LedDIO2','LedDAQ','LedSUpply')) {
    \$d = \$d -replace \"(Me\.\$led\.Size = New System\.Drawing\.Size\(25, 25\))`r?`n(\s+Me\.\$led\.TabIndex)\", \"`\$1`r`n        Me.\$led.BackColor = System.Drawing.Color.Gray`r`n\`\$2\"
}

# --- 9. Button에 FlatStyle 추가 ---
foreach (\$btn in @('ascButtonExit','axcButtonPart','axcButtonSEt','axcButtonSearch','axcButtonSIgnal','AxcButtonCountReset','ascButtonTest','ascButtonTestSearch')) {
    \$d = \$d -replace \"(Me\.\$btn\.Size = New System\.Drawing\.Size\(\d+, \d+\))`r?`n(\s+Me\.\$btn\.TabIndex)\", \"`\$1`r`n        Me.\$btn.FlatStyle = System.Windows.Forms.FlatStyle.Flat`r`n\`\$2\"
}

# --- 10. Label에 TextAlign + BorderStyle 추가 (값표시 라벨들) ---
# 이건 너무 많아서 일괄 처리 어려움. 주요 라벨들만.

# 연속 빈줄 정리
\$d = \$d -replace '(\r?\n){4,}', \"`r`n`r`n\"

[System.IO.File]::WriteAllText('FrmMain.Designer.vb', \$d, [System.Text.Encoding]::UTF8)
Write-Host 'Designer.vb 교체 완료'
Write-Host ('줄 수: ' + (\$d -split \"`r?`n\").Count)
"

