$base = "C:\Users\Administrator\Desktop\리크 검사기 신진&엔케이\신진"
$file = Join-Path $base "FrmMain.Designer.vb"

# 백업
Copy-Item $file "$file.bak" -Force

$d = [System.IO.File]::ReadAllText($file, [System.Text.Encoding]::UTF8)

# --- 1. 생성부: 버튼 ---
$buttons = @('ascButtonExit','axcButtonPart','axcButtonSEt','axcButtonSearch','axcButtonSIgnal','AxcButtonCountReset','ascButtonTest','ascButtonTestSearch')
foreach ($btn in $buttons) {
    $d = $d -replace "Me\.$btn = New AxCWUIControlsLib\.AxCWButton\(\)", "Me.$btn = New System.Windows.Forms.Button()"
}

# --- LED 패널 ---
$leds = @('LedScanner','LedPrinter','LedDIO','LedDIO2','LedDAQ','LedSUpply')
foreach ($led in $leds) {
    $d = $d -replace "Me\.$led = New AxCWUIControlsLib\.AxCWButton\(\)", "Me.$led = New System.Windows.Forms.Panel()"
}

# --- 나머지 AxCWButton → Label ---
$d = $d -replace 'New AxCWUIControlsLib\.AxCWButton\(\)', 'New System.Windows.Forms.Label()'

# --- ScatterGraph → ZedGraphControl ---
$d = $d -replace 'New NationalInstruments\.UI\.WindowsForms\.ScatterGraph\(\)', 'New ZedGraph.ZedGraphControl()'

# --- FlexCell.Grid → DataGridView ---
$d = $d -replace 'New FlexCell\.Grid\(\)', 'New System.Windows.Forms.DataGridView()'

# --- ScatterPlot/XAxis/YAxis/XYCursor/XYRangeAnnotation 생성줄 제거 ---
$lines = $d -split "`r?`n"
$filtered = [System.Collections.Generic.List[string]]::new()
foreach ($line in $lines) {
    if ($line -match 'Me\.(ScatterPlot\d+|XAxis\d+|YAxis\d+|XyCursor\d+|XyRangeAnnotation\d+|Range\d+\w+) = New NationalInstruments\.UI\.' -and $line -notmatch 'srcGraph') {
        continue
    }
    $filtered.Add($line)
}
$d = $filtered -join "`r`n"

# --- BeginInit/EndInit 제거 (NI/AxCW 관련) ---
$lines = $d -split "`r?`n"
$filtered = [System.Collections.Generic.List[string]]::new()
foreach ($line in $lines) {
    if ($line -match 'CType\(Me\.' -and ($line -match 'BeginInit' -or $line -match 'EndInit') -and $line -notmatch 'acquisitionDataGrid') {
        # acquisitionDataGrid는 유지, 나머지 NI/AxCW는 제거
        if ($line -match 'CType\(Me\.(XyCursor|ScatterPlot\d|XAxis\d|YAxis\d|srcGraph|lbCellType|src\d|src1|AxCW|_1st_Lb|asc|axc|Led|Axc)') {
            continue
        }
    }
    $filtered.Add($line)
}
$d = $filtered -join "`r`n"

# --- OcxState 줄 제거 ---
$lines = $d -split "`r?`n"
$filtered = [System.Collections.Generic.List[string]]::new()
foreach ($line in $lines) {
    if ($line -match '\.OcxState\s*=') { continue }
    $filtered.Add($line)
}
$d = $filtered -join "`r`n"

# --- ScatterPlot/XAxis/YAxis/XyCursor/Range 속성 줄 제거 ---
$lines = $d -split "`r?`n"
$filtered = [System.Collections.Generic.List[string]]::new()
foreach ($line in $lines) {
    if ($line -match '^\s+Me\.(ScatterPlot\d+|XAxis\d+|YAxis\d+|XyCursor\d+)\.' -and $line -notmatch 'srcGraph') { continue }
    if ($line -match '^\s+Me\.(Range\d+\w+|XyRangeAnnotation\d+)\.' -and $line -notmatch 'srcGraph') { continue }
    $filtered.Add($line)
}
$d = $filtered -join "`r`n"

# --- ScatterPlot/XAxis/YAxis/XyCursor/Range 주석 블록 제거 ---
$lines = $d -split "`r?`n"
$filtered = [System.Collections.Generic.List[string]]::new()
$i = 0
while ($i -lt $lines.Count) {
    if ($i + 2 -lt $lines.Count -and $lines[$i] -match "^\s+'$" -and $lines[$i+1] -match "^\s+'(ScatterPlot\d+|XAxis\d+|YAxis\d+|XyCursor\d+|Range\d+\w+|XyRangeAnnotation\d+)$" -and $lines[$i+2] -match "^\s+'$") {
        $i += 3
        continue
    }
    $filtered.Add($lines[$i])
    $i++
}
$d = $filtered -join "`r`n"

# --- srcGraph NI전용 속성 제거 ---
$lines = $d -split "`r?`n"
$filtered = [System.Collections.Generic.List[string]]::new()
$skipMultiline = $false
foreach ($line in $lines) {
    if ($skipMultiline) {
        if ($line -match 'GraphInteractionModes\)$') {
            $skipMultiline = $false
        }
        continue
    }
    if ($line -match '^\s+Me\.srcGraph\w+\.(Border|Caption|CaptionFont|PlotAreaColor|UseColorGenerator)\s*=') { continue }
    if ($line -match '^\s+Me\.srcGraph\w+\.InteractionMode\s*=') {
        $skipMultiline = $true
        continue
    }
    if ($line -match '^\s+Me\.srcGraph\w+\.(Plots|XAxes|YAxes|Annotations)\.AddRange') { continue }
    $filtered.Add($line)
}
$d = $filtered -join "`r`n"

# --- GridCount FlexCell 속성 교체 ---
$d = $d -replace 'Me\.GridCount\.BorderStyle = FlexCell\.BorderStyleEnum\.FixedSingle', 'Me.GridCount.BorderStyle = System.Windows.Forms.BorderStyle.FixedSingle'
$d = $d -replace 'Me\.GridCount\.ScrollBars = FlexCell\.ScrollBarsEnum\.None', 'Me.GridCount.ScrollBars = System.Windows.Forms.ScrollBars.None'

# GridCount FlexCell 전용 속성 제거
$lines = $d -split "`r?`n"
$filtered = [System.Collections.Generic.List[string]]::new()
foreach ($line in $lines) {
    if ($line -match '^\s+Me\.GridCount\.(CheckedImage|DefaultFont|DefaultRowHeight|GridColor|UncheckedImage)\s*=') { continue }
    $filtered.Add($line)
}
$d = $filtered -join "`r`n"

# --- Friend WithEvents 선언부 교체 ---
foreach ($btn in $buttons) {
    $d = $d -replace "Friend WithEvents $btn As AxCWUIControlsLib\.AxCWButton", "Friend WithEvents $btn As System.Windows.Forms.Button"
}
foreach ($led in $leds) {
    $d = $d -replace "Friend WithEvents $led As AxCWUIControlsLib\.AxCWButton", "Friend WithEvents $led As System.Windows.Forms.Panel"
}
$d = $d -replace 'Friend WithEvents (\w+) As AxCWUIControlsLib\.AxCWButton', 'Friend WithEvents $1 As System.Windows.Forms.Label'

# ScatterGraph → ZedGraphControl
$d = $d -replace 'Friend WithEvents (\w+) As WindowsForms\.ScatterGraph', 'Friend WithEvents $1 As ZedGraph.ZedGraphControl'

# FlexCell.Grid → DataGridView
$d = $d -replace 'Friend WithEvents GridCount As FlexCell\.Grid', 'Friend WithEvents GridCount As System.Windows.Forms.DataGridView'

# ScatterPlot, XAxis, YAxis, XYCursor, XYRangeAnnotation 선언 제거
$lines = $d -split "`r?`n"
$filtered = [System.Collections.Generic.List[string]]::new()
foreach ($line in $lines) {
    if ($line -match 'Friend WithEvents \w+ As (ScatterPlot|XAxis|YAxis|XYCursor|XYRangeAnnotation)$') { continue }
    $filtered.Add($line)
}
$d = $filtered -join "`r`n"

# --- LED Panel BackColor 추가 ---
foreach ($led in $leds) {
    $d = $d -replace "(Me\.$led\.Size = New System\.Drawing\.Size\(25, 25\))\r?\n(\s+Me\.$led\.TabIndex)", "`$1`r`n        Me.$led.BackColor = System.Drawing.Color.Gray`r`n`$2"
}

# --- Button FlatStyle 추가 ---
foreach ($btn in $buttons) {
    $d = $d -replace "(Me\.$btn\.Size = New System\.Drawing\.Size\(\d+, \d+\))\r?\n(\s+Me\.$btn\.TabIndex)", "`$1`r`n        Me.$btn.FlatStyle = System.Windows.Forms.FlatStyle.Flat`r`n`$2"
}

# --- 연속 빈줄 정리 ---
$d = $d -replace "(\r?\n){4,}", "`r`n`r`n"

[System.IO.File]::WriteAllText($file, $d, [System.Text.Encoding]::UTF8)
Write-Host "Designer.vb 교체 완료"
Write-Host ("줄 수: " + ($d -split "`r?`n").Count)

